3	//! `SYS_GETINFO` — kernel-state introspection.
4	//!
5	//! The request sub-type lives in the first 4 bytes of the message payload
6	//! (mirrors MINIX 3 `mess_lsys_krn_sys_getinfo.request`). Phase 2 implements
7	//! only `GET_WHOAMI`; every other sub-type returns `EINVAL` so a stub that
8	//! sends an unsupported request gets a recognizable error rather than a
9	//! silently-zeroed reply.
10	
11	use minixrs_kernel_shared::callnr::{GET_WHOAMI, SYS_GETINFO_NAME_LEN};
12	use minixrs_kernel_shared::error::{EINVAL, OK};
13	use minixrs_kernel_shared::message::Message;
14	
15	use crate::proc::proc_struct::PROC_NAME_LEN;
16	use crate::proc::{Priv, Proc};
17	
18	// The GET_WHOAMI reply embeds `caller.name` verbatim, so the kernel's
19	// per-slot name field and the wire-format name field must stay the same
20	// size. If `PROC_NAME_LEN` ever changes, update `SYS_GETINFO_NAME_LEN`
21	// (and the layout-table comment below) to match.
22	const _: () = assert!(PROC_NAME_LEN == SYS_GETINFO_NAME_LEN);
23	
24	/// `SYS_GETINFO` entry point. Dispatches by request sub-type.
25	pub(super) fn do_getinfo(caller: &mut Proc, caller_priv: &Priv, msg: &mut Message) -> i32 {
26	    let request = i32::from_ne_bytes(
27	        msg.payload[0..4]
28	            .try_into()
29	            .expect("payload is at least 4 bytes"),
30	    );
31	    match request {
32	        GET_WHOAMI => fill_whoami(caller, caller_priv, msg),
33	        _ => EINVAL,
34	    }
35	}
36	
37	/// `GET_WHOAMI` reply — fills `msg.payload` in-place. Layout:
38	///
39	/// | offset  | type     | meaning                            |
40	/// |---------|----------|------------------------------------|
41	/// |   0..4  | i32      | caller endpoint                    |
42	/// |   4..8  | i32      | `Priv::flags`, zero-extended       |
43	/// |   8..12 | i32      | init flags (always 0 for Phase 2)  |
44	/// |  12..28 | [u8; 16] | `Proc::name`, NUL-padded           |
45	fn fill_whoami(caller: &Proc, caller_priv: &Priv, msg: &mut Message) -> i32 {
46	    msg.payload[0..4].copy_from_slice(&caller.endpoint.to_ne_bytes());
47	    msg.payload[4..8].copy_from_slice(&(caller_priv.flags as i32).to_ne_bytes());
48	    msg.payload[8..12].copy_from_slice(&0_i32.to_ne_bytes());
49	    msg.payload[12..12 + PROC_NAME_LEN].copy_from_slice(&caller.name);
50	    OK
51	}
52

