        let mut m = msg(boot_endpoint(PM_PROC_NR), SEF_SIGNAL);
        m.payload[0..4].copy_from_slice(&9i32.to_ne_bytes());
        assert_eq!(classify(&m), SefEvent::Signal(9));
    }

